  ('aboriginal-f0899a01-moex-00500', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '已著手於犯罪行為之實行而不遂者，為下列何種犯罪類型？', '["未遂犯", "既遂犯", "預備犯", "陰謀犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "e6e107130816", "answer_pdf_sha1": "1c2f06e63016", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00501', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '共犯與正犯之關係，依刑法立法理由，我國刑法係採下列何種「從屬形式」？', '["極端從屬形式", "嚴格從屬形式", "限制從屬形式", "最小從屬形式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "e6e107130816", "answer_pdf_sha1": "1c2f06e63016", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
